import styled from "styled-components";
import { getColors } from "../../Styles/colors";

export const Container = styled.div`
  width: 100%;
  height: 12rem;
  margin: 2rem 0;
  border: 1px solid ${(props) => getColors(props.theme).accent};
`;

export const ImageWrapper = styled.div`
  height: 100%;
  width: 24rem;
`;
